/* -------------------------------------------------------------------------- */
/*                              UTILITY FUCTIONS                              */
/* -------------------------------------------------------------------------- */
/**
 * @returns {string}
 */
function createId() {
    const values = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz_";
    let str = Date.now() + "";
    for (let i = 0; i < 8; i++) {
        const indexValue = Math.floor(Math.random() * values.length);
        const indexPosition = Math.floor(Math.random() * str.length);
        str = str.slice(0, indexPosition) + values[indexValue] + str.slice(indexPosition);
    }
    return str;
}

/* -------------------------------------------------------------------------- */
/*                                 STATES                                     */
/* -------------------------------------------------------------------------- */
/**
 * @typedef {{
 *  color: "none" | "purple" | "red" | "green" | "brown" | "yellow" | "blue" | "pink",
 *  completed: boolean,
 *  date: Date,
 *  id: string,
 *  tags: string[],
 *  text: "string",
 * }} TodoItem
 */

/**
 * @param {{
 *  text: string,
 *  color: "none" | "purple" | "red" | "green" | "brown" | "yellow" | "blue" | "pink",
 *  tags: string[],
 * }} item 
 * @returns {TodoItem}
 */
const createTodoState = ({text = "Nothing", color = "none", tags = []}) => {
    const id = createId();
    const obj = {
        color,
        completed: false,
        date: Date.now(),
        id,
        tags,
        text,
    };
    return [id, obj];
}

const editTodoState = (original, {text = "", color = "",tags, dateNow = false}) => {
    return {
        color: color ? color : original.color,
        completed: original.completed,
        date: dateNow ? Date.now() : original.date,
        id: original.id,
        tags: Array.isArray(tags) ? tags : original.tags,
        text: text ? text : original.text
    }
} 

const setInitTodosState = () => {
    const localTodos =  JSON.parse(localStorage.getItem("todos"));
    if (localTodos == null) {
        localStorage.setItem('todos', JSON.stringify({}));
        return {};
    } 
    return localTodos;
}

const initTodosState = setInitTodosState();

/* -------------------------------------------------------------------------- */
/*                                  REDUCERS                                  */
/* -------------------------------------------------------------------------- */
function todosReducer(state = initTodosState, action) {
    switch (action.type) {
        case 'todos/todoAdded': {
            const [id, newTodo] = createTodoState(action.payload);
            const todos = { ...state, [id]: newTodo }; 
            localStorage.setItem("todos", JSON.stringify(todos));
            return todos;
        }
        case 'todos/allCompleted': {
            const newTodos = {...state};
            Object.keys(newTodos).forEach(key => newTodos[key].completed = true);
            localStorage.setItem("todos", JSON.stringify(newTodos));
            return newTodos;
        }
        case 'todos/completedCleared': {
            const newTodos = {...state};
            for (const key in newTodos) {
                if (newTodos[key].completed) {
                    delete newTodos[key];
                }
            }
            localStorage.setItem("todos", JSON.stringify(newTodos));
            return newTodos;
        }
        case 'todos/todoDeleted': {
            const id = action.payload;
            if (id in state) {
                const newState = {...state};
                delete newState[id];
                localStorage.setItem("todos", JSON.stringify(newState));
                return newState;
            }
            return state;
        }
        case 'todos/todoEdit': {
            const id = action.payload.id;
            if (id in state) {
                const editTodo = editTodoState(state[id], action.payload.todo);
                const newState = { ...state, [id]: editTodo }
                localStorage.setItem("todos", JSON.stringify(newState));
                return newState;
            }
            return state;
        }
        case 'todos/todoToggled': {
            const id = action.payload;
            if (id in state) {
                const todo = {...state[id]};
                todo.completed = !todo.completed;
                const newState = { ...state, [id]: todo };
                localStorage.setItem("todos", JSON.stringify(newState));
                return newState;
            } 
            return state;
        }
        default: 
            return state;
    }
}

export { todosReducer }
